INSERT INTO `reportes_incidencias` VALUES (1,'Oscar / Jefe de Producción ',1,'0101199000377','Falta de Respeto','Fue irrespetuosos con sus compañeros y demás compañero hablando malas palabras groseras y refiriéndose hacia mi como una persona cualquiera  ','Despido ','Urgente',NULL,'En Proceso',10,'2026-06-09 16:44:24','2026-06-12 14:22:48'),(2,'Oscar / Jefe de Produccion',1,'0101199000377','Pelea','se puso a peliar a golpes con migo porque le di una orden de darme un tipo de material para agilizar la orden 701 y se enojo y se me vino a los golpes','Pelea con migo ','Alta','/uploads/tickets/incidencia-1781025489152.jpg','Resuelto',10,'2026-06-09 17:18:09','2026-06-12 16:53:24'),(5,'Hillary Cole',5,'0101-1990-00377','Desempeño','No realiza bien su trabajo ya que llevamos una semana corrigiendo y desecha mucho la materia prima y las maquinas las golpea ','Hace mal su trabajo','Media',NULL,'Cancelado',11,'2026-06-10 14:28:51','2026-06-12 21:27:38'),(6,'Oscar/ Jefe de Producción ',1,'0101199000377','Pelea','Sigue Denilson peleando, ya mucho se va a los golpes','Pelea de Nuevo ','Alta',NULL,'Resuelto',11,'2026-06-12 20:16:55','2026-06-23 20:36:54'),(7,'Carlos / Jefe de Ventas',1,'0101199000377','Llegada Tarde','Llego tarde porque se durmió ','Llego Tarde','Media',NULL,'Resuelto',11,'2026-06-22 21:53:53','2026-06-23 18:31:53'),(8,'Oscar/ Jefe Produccion',1,'0101199000377','General','No quiere trabajar','No quiere Trabajar','Media',NULL,'Resuelto',11,'2026-06-23 16:14:16','2026-07-01 20:39:07'),(10,'Tommy Cole/ Jefe Venta',15,'0106-2000-00019','Pelea','Se puso a bromear pesado con los compañeros y se puso a pelear con los demás empleados en grupo','Pelea con un grupo de compañeros','Urgente','/uploads/incidencias/incidencia-1782921350287.jpg','En Proceso',10,'2026-07-01 15:55:50','2026-07-01 16:11:21'),(11,'Tommy Cole',17,'0101-1994-00528','Insubordinación','Se le esta diciendo ordenes desde ya varios dias y repitiendo que tiene que visitar un cliente y no obedece, el cliente esta muy enojado ','No acata Ordenes ','Urgente',NULL,'Pendiente',NULL,'2026-07-01 16:49:53','2026-07-01 16:49:53'),(12,'Usuario',NULL,'0105200200886','Pelea','Se puso a bromear y se peleo con un grupo de sus compaeros ','Armo Pelea con Compaeros','Urgente','/uploads/incidencias/incidencia-1783092682024.jpg','Pendiente',NULL,'2026-07-03 15:31:22','2026-07-03 15:31:22'),(16,'Hillary Cole',25,'0105-2002-00886','General','Peleon ','Peleon','Urgente',NULL,'En Proceso',NULL,'2026-07-03 16:15:42','2026-07-08 17:14:45'),(17,'Daniel Innova',17,'0101-1994-00528','Pelea','Se puso a pelear con Denison y creo que gano ','Se Puso a pelear con Denisson ','Urgente','/uploads/incidencias/incidencia-1783095657752.jpg','En Proceso',9,'2026-07-03 16:20:57','2026-07-03 16:26:00'),(19,'Gerad Cole',NULL,'0501-1992-06929, 0101-2001-04165','Abandono de Trabajo','Llegaron al trabajo marcaron normal y luego se fueron como si nada abandonando el trabajo ','abandonaron el trabajo','Media','/uploads/incidencias/incidencia-1783113866767.png','Pendiente',NULL,'2026-07-03 21:24:26','2026-07-03 21:24:26'),(20,'Kevin Valladares',NULL,'0105-2002-00886, 0101-1994-00528, 0101-1992-02845','Pelea','Se pusieron a pelear porque no les habían hecho una ventana a tiempo ','Se Pusieron a pelear en grupo ','Media','/uploads/incidencias/incidencia-1783114732637.png','Pendiente',NULL,'2026-07-03 21:38:52','2026-07-03 21:38:52'),(22,'Oscar/ Jefe Produccion',NULL,'0101-1981-00820, 0501-1992-06929, 0101-1998-00137','Abandono de Trabajo','Se fue porque querria ver los goles de Mesi','Se Fueron a ver los partidos del mundial','Media',NULL,'En Proceso',14,'2026-07-03 22:39:45','2026-07-09 15:14:44'),(23,'Carlos / Jefe Sala Ventas',7,'0101-1982-01108','Incumplimiento','Hace 3 meses que no me tiene la orden y solo son promesas ya van 3 veces que me dice que van estar lista y no cumple.','Orden 9015','Urgente',NULL,'Pendiente',NULL,'2026-07-07 17:02:16','2026-07-07 17:02:16');
