INSERT INTO `ticket_respuestas` VALUES (1,18,9,NULL,'Buenos días Karin Beckan le saluda Carlos Flores.\r\n de acuerdo con su solicitud y revisando el caso se le dispensara las fechas 19,20,21 ya que creemos que tiene que viajar un dia antes a la ciudad de Tegucigalpa y Retornar y el viaje es de 7 horas mas el regreso. Es por ello que vemos factible que usted realice su viaje con tranquilidad y regrese motivado a su trabajo. \r\n\r\nBuena Suerte en su petición de Visado ',NULL,'2026-05-18 16:43:15'),(2,18,9,NULL,'Daniel por favor responder',NULL,'2026-05-18 17:08:50'),(3,18,NULL,4,'Si Danie Porfavor contésteme 😁 ',NULL,'2026-05-18 18:12:07'),(4,19,9,NULL,'HOL',NULL,'2026-05-18 18:25:51'),(5,19,NULL,2,'TENGO MALA LA PC',NULL,'2026-05-18 18:26:55'),(6,18,9,NULL,'RESUELTO',NULL,'2026-05-18 18:27:39'),(36,17,4,NULL,'Hola Luis trate de reiniciarlo por favor y luego me avisa si se soluciono el problema de la señal',NULL,'2026-07-06 17:50:11'),(37,17,4,17,'Listo Daniel ya regreso la señal gracias ',NULL,'2026-07-06 17:54:21'),(38,17,4,NULL,'Excelente Luis Fernando, cambiare su estado a resuelto\r\n',NULL,'2026-07-06 17:55:48');
